code = """import json

# Load business data
businesses = var_functions.query_db:26

# Extract categories from descriptions
def extract_categories(description):
    if not description or 'services' not in str(description).lower():
        return []
    
    # Look for patterns like "services in X, Y, and Z" or "including X, Y, and Z"
    desc = str(description)
    categories = []
    
    # Pattern 1: "services in" followed by list
    if 'services in' in desc:
        parts = desc.split('services in')
        if len(parts) > 1:
            category_part = parts[1].split('.')[0].split('and')
            for part in category_part:
                cats = part.replace('including', '').replace('and', '').strip()
                if ',' in cats:
                    for cat in cats.split(','):
                        cat = cat.strip()
                        if cat and len(cat) < 100:
                            categories.append(cat)
                else:
                    cat = cats.strip()
                    if cat and len(cat) < 100:
                        categories.append(cat)
    
    # Pattern 2: "including" followed by list
    elif 'including' in desc:
        parts = desc.split('including')
        if len(parts) > 1:
            category_part = parts[1].split('.')[0].split('and')
            for part in category_part:
                cats = part.strip()
                if ',' in cats:
                    for cat in cats.split(','):
                        cat = cat.strip()
                        if cat and len(cat) < 100:
                            categories.append(cat)
                else:
                    cat = cats.strip()
                    if cat and len(cat) < 100:
                        categories.append(cat)
    
    return categories

# Create mapping: business_ref -> categories
business_to_categories = {}
for business in businesses:
    business_id = business['business_id']  # e.g., businessid_49
    business_ref = business_id.replace('businessid_', 'businessref_')
    
    desc = business.get('description', '')
    cats = extract_categories(desc)
    
    # Clean up categories
    cleaned_cats = []
    for cat in cats:
        # Remove trailing punctuation
        cat = cat.rstrip('.').rstrip(',').strip()
        if cat:
            cleaned_cats.append(cat)
    
    business_to_categories[business_ref] = cleaned_cats

# Show some examples
examples = []
for i, (bref, cats) in enumerate(business_to_categories.items()):
    if i < 3:
        examples.append({'business_ref': bref, 'categories': cats})

print('__RESULT__:')
print(json.dumps({
    'business_count': len(business_to_categories),
    'examples': examples[:3]
}, indent=2))"""

